const router = require('express').Router();
const User = require('../models/User');
const Professor = require('../models/Professor');
const Admin = require('../models/Admin');
const jwt = require('jsonwebtoken');
const admin = require('firebase-admin');
const nodemailer = require('nodemailer');
const speakeasy = require('speakeasy');

// -------------------- Firebase Admin Setup --------------------
if (!admin.apps.length) {
  admin.initializeApp({
    credential: admin.credential.cert({
      projectId: process.env.FIREBASE_PROJECT_ID,
      privateKey: process.env.FIREBASE_PRIVATE_KEY?.replace(/\\n/g, '\n'),
      clientEmail: process.env.FIREBASE_CLIENT_EMAIL,
    }),
  });
}

// -------------------- Nodemailer Setup --------------------
const transporter = nodemailer.createTransport({
  host: process.env.SMTP_HOST,
  port: process.env.SMTP_PORT,
  secure: false, // true for 465
  auth: {
    user: process.env.SMTP_USER,
    pass: process.env.SMTP_PASS,
  },
});

// Temporary OTP store for email OTPs (in production use Redis/Database)
const otpStore = new Map(); // key: email, value: { secret, expires }

// ---------- Student OTP (Firebase Phone Auth) ----------
// @route   POST /api/auth/request-otp
// @desc    Request OTP – now just acknowledges that frontend will trigger Firebase
// @access  Public
router.post('/request-otp', async (req, res) => {
  const { mobile } = req.body;
  if (!mobile) {
    return res.status(400).json({ error: 'Mobile number is required' });
  }
  // Firebase phone auth is client‑side; we only log and return a success message.
  console.log(`📱 Firebase OTP requested for ${mobile}`);
  res.json({ message: 'OTP sent via Firebase' });
});

// @route   POST /api/auth/verify-otp
// @desc    Verify Firebase ID token and login/register student
// @access  Public
router.post('/verify-otp', async (req, res) => {
  try {
    const { idToken, email, username } = req.body; // idToken from Firebase client
    if (!idToken) {
      return res.status(400).json({ error: 'ID token is required' });
    }

    // Verify the Firebase token
    const decodedToken = await admin.auth().verifyIdToken(idToken);
    const mobile = decodedToken.phone_number;
    if (!mobile) {
      return res.status(400).json({ error: 'Phone number not found in token' });
    }

    let user = await User.findOne({ mobile });

    if (!user) {
      // New user: require email and username
      if (!email || !username) {
        return res.status(400).json({ error: 'Email and username required for new user' });
      }
      const existingUser = await User.findOne({ username });
      if (existingUser) {
        return res.status(400).json({ error: 'Username already taken' });
      }
      user = new User({ mobile, email, username });
      await user.save();
    }

    const token = jwt.sign(
      { id: user._id, mobile: user.mobile, role: user.role },
      process.env.JWT_SECRET,
      { expiresIn: '7d' }
    );

    res.json({
      token,
      user: {
        id: user._id,
        mobile: user.mobile,
        email: user.email,
        username: user.username,
        name: user.name,
        role: user.role,
        studyTokens: user.studyTokens,
        dailyStreak: user.dailyStreak,
        rollNo: user.rollNo,
        lastScan: user.lastScan,
        scanCountToday: user.scanCountToday,
      },
    });
  } catch (err) {
    console.error('❌ Firebase token verification error:', err);
    res.status(500).json({ error: 'Invalid or expired OTP' });
  }
});

// ---------- Professor OTP (Email) ----------
// @route   POST /api/auth/professor/request-otp
// @desc    Send OTP to professor email
// @access  Public
router.post('/professor/request-otp', async (req, res) => {
  const { email } = req.body;
  if (!email) {
    return res.status(400).json({ error: 'Email is required' });
  }

  try {
    // Generate OTP secret
    const secret = speakeasy.generateSecret({ length: 20 });
    const otp = speakeasy.totp({
      secret: secret.base32,
      encoding: 'base32',
      step: 300, // 5 minutes
      digits: 6,
    });

    // Store secret with expiry (5 minutes)
    otpStore.set(email, {
      secret: secret.base32,
      expires: Date.now() + 5 * 60 * 1000,
    });

    // Send email
    const mailOptions = {
      from: process.env.OTP_EMAIL_FROM,
      to: email,
      subject: 'Your StudySnap Login OTP',
      text: `Your OTP is: ${otp}. It is valid for 5 minutes.`,
      html: `<p>Your OTP is: <strong>${otp}</strong></p><p>It is valid for 5 minutes.</p>`,
    };
    await transporter.sendMail(mailOptions);

    console.log(`📧 OTP sent to ${email}`);
    res.json({ message: 'OTP sent to email' });
  } catch (err) {
    console.error('❌ Email OTP error:', err);
    res.status(500).json({ error: 'Failed to send OTP' });
  }
});

// @route   POST /api/auth/professor/verify-otp
// @desc    Verify OTP and login professor
// @access  Public
router.post('/professor/verify-otp', async (req, res) => {
  try {
    const { email, otp } = req.body;
    if (!email || !otp) {
      return res.status(400).json({ error: 'Email and OTP required' });
    }

    const stored = otpStore.get(email);
    if (!stored || stored.expires < Date.now()) {
      return res.status(400).json({ error: 'OTP expired or not requested' });
    }

    const isValid = speakeasy.totp.verify({
      secret: stored.secret,
      encoding: 'base32',
      token: otp,
      step: 300,
      window: 1,
      digits: 6,
    });

    if (!isValid) {
      return res.status(400).json({ error: 'Invalid OTP' });
    }

    // Clear used OTP
    otpStore.delete(email);

    // Find or create professor (if not exists, they must have registered via password)
    let professor = await Professor.findOne({ email }).populate('college');
    if (!professor) {
      return res.status(404).json({ error: 'Professor not registered. Please sign up first.' });
    }

    if (!professor.approved) {
      return res.status(403).json({ error: 'Account pending admin approval' });
    }

    const token = jwt.sign(
      { id: professor._id, email: professor.email, role: 'professor' },
      process.env.JWT_SECRET,
      { expiresIn: '7d' }
    );

    res.json({
      token,
      professor: {
        id: professor._id,
        name: professor.name,
        email: professor.email,
        college: professor.college,
        courses: professor.courses,
        approved: professor.approved,
      },
    });
  } catch (err) {
    console.error('❌ Professor OTP verification error:', err);
    res.status(500).json({ error: 'Server error' });
  }
});

